// ADD BEFORE: const updatedUser = await userRepository.updateLocation(...)

// Check capacity if joining a space
if (spaceId) {
  const { data: space } = await supabase
    .from('spaces')
    .select('capacity')
    .eq('id', spaceId)
    .single();

  if (space?.capacity && space.capacity > 0) {
    const { count } = await supabase
      .from('users')
      .select('id', { count: 'exact', head: true })
      .eq('current_space_id', spaceId);

    if (count && count >= space.capacity) {
      return NextResponse.json(
        { error: 'Space is full', code: 'SPACE_FULL' },
        { status: 409 }
      );
    }
  }
}

